local LATIN_UPPER = {
    ["à"] = "À", ["á"] = "Á", ["â"] = "Â", ["ã"] = "Ã",
    ["è"] = "È", ["é"] = "É", ["ê"] = "Ê",
    ["ì"] = "Ì", ["í"] = "Í", ["î"] = "Î",
    ["ñ"] = "Ñ",
    ["ò"] = "Ò", ["ó"] = "Ó", ["ô"] = "Ô", ["õ"] = "Õ",
    ["ù"] = "Ù", ["ú"] = "Ú", ["û"] = "Û",
    ["ā"] = "Ā", ["ē"] = "Ē", ["ĩ"] = "Ĩ", ["ī"] = "Ī",
    ["ń"] = "Ń", ["ō"] = "Ō", ["ũ"] = "Ũ", ["ū"] = "Ū",
    ["ǹ"] = "Ǹ", ["ḿ"] = "Ḿ", ["ṳ"] = "Ṳ", ["ẽ"] = "Ẽ",
    ["ǎ"] = "Ǎ", ["ě"] = "Ě", ["ǐ"] = "Ǐ", ["ǒ"] = "Ǒ", ["ǔ"] = "Ǔ",
    ["ǖ"] = "Ǖ", ["ǘ"] = "Ǘ", ["ǚ"] = "Ǚ", ["ǜ"] = "Ǜ",
}

local function capitalize_first(text)
    if not text or text == "" then return text end
    local first = utf8.char(utf8.codepoint(text, 1))
    local upper = LATIN_UPPER[first] or first:upper()
    return upper .. text:sub(utf8.offset(text, 2) or (#text + 1))
end

local _caps_mask = ""

local function processor(key, env)
    if key:release() then return 2 end
    local ctx = env.engine.context
    local kc = key.keycode

    local n = #ctx.input
    if #_caps_mask > n then
        _caps_mask = _caps_mask:sub(1, n)
    end

    if kc == 8 then
        if #_caps_mask > 0 then
            _caps_mask = _caps_mask:sub(1, #_caps_mask - 1)
        end
        return 2
    end

    local is_uppercase_letter = (kc >= 65 and kc <= 90) or (kc >= 97 and kc <= 122 and (key:shift() or key:caps()))
    if is_uppercase_letter then
        _caps_mask = _caps_mask .. "U"
    elseif (kc >= 97 and kc <= 122) or (kc >= 48 and kc <= 57) or kc == 45 then
        _caps_mask = _caps_mask .. "_"
    end

    return 2
end

local function get_caps_mask(env)
    local ctx = env.engine.context
    local n = #ctx.input
    local caps = _caps_mask
    if #caps > n then caps = caps:sub(1, n) end
    while #caps < n do caps = caps .. "_" end
    return caps
end



local function is_han_char(text)
    if not text or #text == 0 then return false end
    local b = string.byte(text, 1)
    if b >= 0xE4 and b <= 0xE9 then return true end
    if b >= 0xF0 then return true end
    return false
end

local function synth_from_input(input)
    local synth = ""
    local si = 1
    while si <= #input do
        local tok = input:match("^[%w]+", si)
        if tok then
            local hw = SYLLABLE_MAP[tok:lower()]
            if not hw then return nil end
            synth = synth .. hw
            si = si + #tok
        else
            local sep = input:match("^[^%w]+", si)
            if sep then synth = synth .. sep; si = si + #sep
            else synth = synth .. input:sub(si, si); si = si + 1 end
        end
    end
    return synth
end

local function filter(translation, env)
    local ctx = env.engine.context
    local caps = _caps_mask
    local has_caps = caps:sub(1, 1) == "U"
    local input = ctx.input or ""
    local has_digits = input:match("%d") ~= nil
    local latin_first = has_caps or has_digits

    local input_syl_count = 0
    if has_digits then
        for _ in input:gmatch("[%w]+") do
            input_syl_count = input_syl_count + 1
        end
    end

    local latin_full = {}
    local latin_partial = {}
    local han_items = {}
    local han_partial = {}

    for cand in translation:iter() do
        if is_han_char(cand.text) then
            local comment = cand.comment or ""
            local hw = comment:gsub("[%w]+", function(code)
                return SYLLABLE_MAP[code:lower()] or code
            end)
            hw = hw:gsub("   ", "--")
            hw = hw:gsub("  ", "-")
            cand.comment = hw
            if latin_first then
                if has_digits and cand._end - cand.start >= #input then
                    local code_count = 0
                    for _ in comment:gmatch("[%w]+") do
                        code_count = code_count + 1
                    end
                    if code_count == input_syl_count then
                        table.insert(han_items, cand)
                    else
                        table.insert(han_partial, cand)
                    end
                else
                    table.insert(han_items, cand)
                end
            else
                yield(cand)
            end
        else
            local comment = cand.comment or ""
            local codes = {}
            for code in comment:gmatch("[%w]+") do
                table.insert(codes, code:lower())
            end
            local syl_mismatch = has_digits and #codes ~= input_syl_count
            local new_text = ""
            local i = 1
            local code_idx = 1
            local valid = true
            while i <= #input do
                local token = input:match("^[%w]+", i)
                if token then
                    local hw = nil
                    local ci = code_idx
                    while ci <= #codes do
                        hw = SYLLABLE_MAP[codes[ci]]
                        if hw then
                            code_idx = ci + 1
                            break
                        end
                        ci = ci + 1
                    end
                    if not hw then
                        hw = SYLLABLE_MAP[token:lower()]
                    end
                    if not hw then
                        valid = false
                        break
                    end
                    new_text = new_text .. hw
                    i = i + #token
                else
                    local sep = input:match("^[^%w]+", i)
                    if sep then
                        new_text = new_text .. sep
                        i = i + #sep
                    else
                        new_text = new_text .. input:sub(i, i)
                        i = i + 1
                    end
                end
            end
            if not valid then new_text = cand.text end
            if has_caps then
                new_text = capitalize_first(new_text)
            end
            local is_full = cand._end - cand.start >= #input and not syl_mismatch
            if new_text ~= cand.text then
                local c = ShadowCandidate(cand, cand.type, new_text, "")
                if latin_first then
                    if is_full then
                        table.insert(latin_full, c)
                    else
                        table.insert(latin_partial, c)
                    end
                else
                    yield(c)
                end
            else
                cand.comment = ""
                if latin_first then
                    if is_full then
                        table.insert(latin_full, cand)
                    else
                        table.insert(latin_partial, cand)
                    end
                else
                    yield(cand)
                end
            end
        end
    end

    if latin_first then
        if #latin_full == 0 and has_digits then
            local synth = synth_from_input(input)
            if synth then
                if has_caps then synth = capitalize_first(synth) end
                local shadowed = false
                for _, hc in ipairs(han_items) do
                    if hc._end - hc.start >= #input then
                        local c = ShadowCandidate(hc, hc.type, synth, "")
                        c.quality = hc.quality + 1000
                        table.insert(latin_full, 1, c)
                        shadowed = true
                        break
                    end
                end
                if not shadowed then
                    local c = Candidate("synth", 0, #input, synth, "")
                    c.quality = 1000
                    table.insert(latin_full, 1, c)
                end
            end
        end
        table.sort(han_items, function(a, b)
            return (a._end - a.start) > (b._end - b.start)
        end)
        for _, c in ipairs(latin_full) do yield(c) end
        for _, c in ipairs(han_items) do yield(c) end
        for _, c in ipairs(latin_partial) do yield(c) end
        for _, c in ipairs(han_partial) do yield(c) end
    end
end

return {{ processor = processor }, filter}
